\sum_{n=&amp;lt;N&amp;gt;}e^{j\frac{2\pi}{N}(k-r)n}
&amp;amp;= \sum_{n=0}^{N-1}e^{j\frac{2\pi}{N}(k-r)n}\\
&amp;amp;= \frac{1-e^{j(k-r)2\pi}}{1-e^{j(k-r)\frac{2\pi}{N}}}\\
&amp;amp;= 
\begin{cases}
0,\ \ \ k\neq r\\
N,\ \ \ k=r
\end{cases}
\end{aligned}
